        "source": "// Idiomatic Rust — callback list of closures. No trait object, no\n// Arc, no Mutex; each registered closure is a plain `Fn(&Event)`.\n// `on()` returns a `SubscriptionId` the caller can use to unsubscribe.\n//\n// Tradeoffs (pick the right form for your concurrency model):\n//\n//   * This file: synchronous, single-threaded, no async runtime needed.\n//     Ideal for in-process event hooks, UI event buses, test spies.\n//\n//   * Multi-threaded: swap `Vec` for `RwLock<Vec<...>>` and add `Send\n//     + Sync` bounds on the closures. See the GoF-style file for the\n//     shape, though channel-based alternatives are usually better.\n//\n//   * Async / multi-subscriber: use `tokio::sync::broadcast` or an\n//     async stream. Each subscriber owns its Receiver / Stream so\n//     registration, unregistration, and backpressure are explicit.\n\nuse std::collections::HashMap;\n\n#[derive(Clone, Debug)]\npub struct Event {\n    pub kind: &'static str,\n    pub payload: String,\n}\n\n#[derive(Copy, Clone, Debug, PartialEq, Eq, Hash)]\npub struct SubscriptionId(u64);\n\npub struct EventBus {\n    next_id: u64,\n    // Key is the SubscriptionId so unsubscribe is O(log n) and order-\n    // stable. The closure is boxed once; no per-emit allocation.\n    callbacks: HashMap<SubscriptionId, Box<dyn Fn(&Event)>>,\n}\n\nimpl EventBus {\n    pub fn new() -> Self {\n        Self { next_id: 0, callbacks: HashMap::new() }\n    }\n\n    #[must_use = \"drop the SubscriptionId and you lose your ability to unsubscribe\"]\n    pub fn on<F: Fn(&Event) + 'static>(&mut self, f: F) -> SubscriptionId {\n        self.next_id += 1;\n        let id = SubscriptionId(self.next_id);\n        self.callbacks.insert(id, Box::new(f));\n        id\n    }\n\n    pub fn off(&mut self, id: SubscriptionId) -> bool {\n        self.callbacks.remove(&id).is_some()\n    }\n\n    pub fn emit(&self, event: &Event) {\n        // Snapshotting the iterator is unnecessary here because `emit`\n        // is `&self` and callbacks cannot mutate the bus through it.\n        // If you changed `on`/`off` to take `&self` + interior mut,\n        // clone the callback Vec before iterating to avoid reentrancy\n        // hazards.\n        for cb in self.callbacks.values() {\n            cb(event);\n        }\n    }\n}\n\nimpl Default for EventBus {\n    fn default() -> Self { Self::new() }\n}\n\nfn main() {\n    let mut bus = EventBus::default();\n\n    let _log = bus.on(|e| println!(\"[log] {} — {}\", e.kind, e.payload));\n    let email = bus.on(|e| {\n        if e.kind == \"user.signup\" {\n            println!(\"[email] welcoming {}\", e.payload);\n        }\n    });\n\n    bus.emit(&Event { kind: \"user.signup\",  payload: \"rajesh@example.com\".into() });\n    bus.emit(&Event { kind: \"user.deleted\", payload: \"someone@example.com\".into() });\n\n    // Unsubscribe. Next emit produces only the log line.\n    assert!(bus.off(email));\n    bus.emit(&Event { kind: \"user.signup\",  payload: \"second@example.com\".into() });\n}\n",
        "playground": "https://play.rust-lang.org/?version=stable&mode=debug&edition=2021&code=%2F%2F%20Idiomatic%20Rust%20%E2%80%94%20callback%20list%20of%20closures.%20No%20trait%20object%2C%20no%0A%2F%2F%20Arc%2C%20no%20Mutex%3B%20each%20registered%20closure%20is%20a%20plain%20%60Fn(%26Event)%60.%0A%2F%2F%20%60on()%60%20returns%20a%20%60SubscriptionId%60%20the%20caller%20can%20use%20to%20unsubscribe.%0A%2F%2F%0A%2F%2F%20Tradeoffs%20(pick%20the%20right%20form%20for%20your%20concurrency%20model)%3A%0A%2F%2F%0A%2F%2F%20%20%20*%20This%20file%3A%20synchronous%2C%20single-threaded%2C%20no%20async%20runtime%20needed.%0A%2F%2F%20%20%20%20%20Ideal%20for%20in-process%20event%20hooks%2C%20UI%20event%20buses%2C%20test%20spies.%0A%2F%2F%0A%2F%2F%20%20%20*%20Multi-threaded%3A%20swap%20%60Vec%60%20for%20%60RwLock%3CVec%3C...%3E%3E%60%20and%20add%20%60Send%0A%2F%2F%20%20%20%20%20%2B%20Sync%60%20bounds%20on%20the%20closures.%20See%20the%20GoF-style%20file%20for%20the%0A%2F%2F%20%20%20%20%20shape%2C%20though%20channel-based%20alternatives%20are%20usually%20better.%0A%2F%2F%0A%2F%2F%20%20%20*%20Async%20%2F%20multi-subscriber%3A%20use%20%60tokio%3A%3Async%3A%3Abroadcast%60%20or%20an%0A%2F%2F%20%20%20%20%20async%20stream.%20Each%20subscriber%20owns%20its%20Receiver%20%2F%20Stream%20so%0A%2F%2F%20%20%20%20%20registration%2C%20unregistration%2C%20and%20backpressure%20are%20explicit.%0A%0Ause%20std%3A%3Acollections%3A%3AHashMap%3B%0A%0A%23%5Bderive(Clone%2C%20Debug)%5D%0Apub%20struct%20Event%20%7B%0A%20%20%20%20pub%20kind%3A%20%26'static%20str%2C%0A%20%20%20%20pub%20payload%3A%20String%2C%0A%7D%0A%0A%23%5Bderive(Copy%2C%20Clone%2C%20Debug%2C%20PartialEq%2C%20Eq%2C%20Hash)%5D%0Apub%20struct%20SubscriptionId(u64)%3B%0A%0Apub%20struct%20EventBus%20%7B%0A%20%20%20%20next_id%3A%20u64%2C%0A%20%20%20%20%2F%2F%20Key%20is%20the%20SubscriptionId%20so%20unsubscribe%20is%20O(log%20n)%20and%20order-%0A%20%20%20%20%2F%2F%20stable.%20The%20closure%20is%20boxed%20once%3B%20no%20per-emit%20allocation.%0A%20%20%20%20callbacks%3A%20HashMap%3CSubscriptionId%2C%20Box%3Cdyn%20Fn(%26Event)%3E%3E%2C%0A%7D%0A%0Aimpl%20EventBus%20%7B%0A%20%20%20%20pub%20fn%20new()%20-%3E%20Self%20%7B%0A%20%20%20%20%20%20%20%20Self%20%7B%20next_id%3A%200%2C%20callbacks%3A%20HashMap%3A%3Anew()%20%7D%0A%20%20%20%20%7D%0A%0A%20%20%20%20%23%5Bmust_use%20%3D%20%22drop%20the%20SubscriptionId%20and%20you%20lose%20your%20ability%20to%20unsubscribe%22%5D%0A%20%20%20%20pub%20fn%20on%3CF%3A%20Fn(%26Event)%20%2B%20'static%3E(%26mut%20self%2C%20f%3A%20F)%20-%3E%20SubscriptionId%20%7B%0A%20%20%20%20%20%20%20%20self.next_id%20%2B%3D%201%3B%0A%20%20%20%20%20%20%20%20let%20id%20%3D%20SubscriptionId(self.next_id)%3B%0A%20%20%20%20%20%20%20%20self.callbacks.insert(id%2C%20Box%3A%3Anew(f))%3B%0A%20%20%20%20%20%20%20%20id%0A%20%20%20%20%7D%0A%0A%20%20%20%20pub%20fn%20off(%26mut%20self%2C%20id%3A%20SubscriptionId)%20-%3E%20bool%20%7B%0A%20%20%20%20%20%20%20%20self.callbacks.remove(%26id).is_some()%0A%20%20%20%20%7D%0A%0A%20%20%20%20pub%20fn%20emit(%26self%2C%20event%3A%20%26Event)%20%7B%0A%20%20%20%20%20%20%20%20%2F%2F%20Snapshotting%20the%20iterator%20is%20unnecessary%20here%20because%20%60emit%60%0A%20%20%20%20%20%20%20%20%2F%2F%20is%20%60%26self%60%20and%20callbacks%20cannot%20mutate%20the%20bus%20through%20it.%0A%20%20%20%20%20%20%20%20%2F%2F%20If%20you%20changed%20%60on%60%2F%60off%60%20to%20take%20%60%26self%60%20%2B%20interior%20mut%2C%0A%20%20%20%20%20%20%20%20%2F%2F%20clone%20the%20callback%20Vec%20before%20iterating%20to%20avoid%20reentrancy%0A%20%20%20%20%20%20%20%20%2F%2F%20hazards.%0A%20%20%20%20%20%20%20%20for%20cb%20in%20self.callbacks.values()%20%7B%0A%20%20%20%20%20%20%20%20%20%20%20%20cb(event)%3B%0A%20%20%20%20%20%20%20%20%7D%0A%20%20%20%20%7D%0A%7D%0A%0Aimpl%20Default%20for%20EventBus%20%7B%0A%20%20%20%20fn%20default()%20-%3E%20Self%20%7B%20Self%3A%3Anew()%20%7D%0A%7D%0A%0Afn%20main()%20%7B%0A%20%20%20%20let%20mut%20bus%20%3D%20EventBus%3A%3Adefault()%3B%0A%0A%20%20%20%20let%20_log%20%3D%20bus.on(%7Ce%7C%20println!(%22%5Blog%5D%20%7B%7D%20%E2%80%94%20%7B%7D%22%2C%20e.kind%2C%20e.payload))%3B%0A%20%20%20%20let%20email%20%3D%20bus.on(%7Ce%7C%20%7B%0A%20%20%20%20%20%20%20%20if%20e.kind%20%3D%3D%20%22user.signup%22%20%7B%0A%20%20%20%20%20%20%20%20%20%20%20%20println!(%22%5Bemail%5D%20welcoming%20%7B%7D%22%2C%20e.payload)%3B%0A%20%20%20%20%20%20%20%20%7D%0A%20%20%20%20%7D)%3B%0A%0A%20%20%20%20bus.emit(%26Event%20%7B%20kind%3A%20%22user.signup%22%2C%20%20payload%3A%20%22rajesh%40example.com%22.into()%20%7D)%3B%0A%20%20%20%20bus.emit(%26Event%20%7B%20kind%3A%20%22user.deleted%22%2C%20payload%3A%20%22someone%40example.com%22.into()%20%7D)%3B%0A%0A%20%20%20%20%2F%2F%20Unsubscribe.%20Next%20emit%20produces%20only%20the%20log%20line.%0A%20%20%20%20assert!(bus.off(email))%3B%0A%20%20%20%20bus.emit(%26Event%20%7B%20kind%3A%20%22user.signup%22%2C%20%20payload%3A%20%22second%40example.com%22.into()%20%7D)%3B%0A%7D%0A"
