">for lazy init</text>\n\n  <rect x=\"480\" y=\"60\" width=\"210\" height=\"110\" rx=\"8\" class=\"mid\"/>\n  <text x=\"585\" y=\"84\" text-anchor=\"middle\" class=\"label\">Mutex&lt;T&gt; inside OnceLock</text>\n  <text x=\"585\" y=\"108\" text-anchor=\"middle\" class=\"sub\">mutable shared state</text>\n  <text x=\"585\" y=\"128\" text-anchor=\"middle\" class=\"sub\">lock on every access</text>\n  <text x=\"585\" y=\"146\" text-anchor=\"middle\" class=\"sub\">deadlock risk</text>\n  <text x=\"585\" y=\"164\" text-anchor=\"middle\" class=\"warn\">only if truly needed</text>\n\n  <rect x=\"250\" y=\"200\" width=\"440\" height=\"90\" rx=\"8\" class=\"bad\"/>\n  <text x=\"470\" y=\"225\" text-anchor=\"middle\" class=\"label\">static mut X: T</text>\n  <text x=\"470\" y=\"245\" text-anchor=\"middle\" class=\"sub\">requires unsafe on every touch</text>\n  <text x=\"470\" y=\"263\" text-anchor=\"middle\" class=\"sub\">no compile-time synchronization guarantee</text>\n  <text x=\"470\" y=\"281\" text-anchor=\"middle\" class=\"warn\">do not use — the error won't surface in dev</text>\n\n  <rect x=\"20\" y=\"200\" width=\"210\" height=\"90\" rx=\"8\" class=\"ok\"/>\n  <text x=\"125\" y=\"225\" text-anchor=\"middle\" class=\"label\">LazyLock&lt;T&gt;</text>\n  <text x=\"125\" y=\"245\" text-anchor=\"middle\" class=\"sub\">OnceLock + init fn</text>\n  <text x=\"125\" y=\"263\" text-anchor=\"middle\" class=\"sub\">auto-derefs to &amp;T</text>\n  <text x=\"125\" y=\"281\" text-anchor=\"middle\" class=\"good\">stable since 1.80</text>\n</svg>\n"
