        "source": "// Sealed Trait — a public trait only your crate's types can implement.\n//\n// Why seal?\n//   * You want to ship `pub trait Format` as a public type-level API\n//     that consumers can use as a bound, without letting them add\n//     implementations you'd then have to support forever.\n//   * You want to refactor internal types freely — adding methods,\n//     changing defaults — without breaking downstream impls that\n//     don't exist.\n//   * You want the compiler to enforce \"this trait is closed\" so\n//     `match kind { Format::Json => ..., Format::Yaml => ... }`\n//     reasoning holds.\n//\n// Mechanism: a *supertrait* the downstream cannot name. Put it in a\n// private module, require it on the public trait, and only implement\n// it for types inside the crate. Downstream impls of the public trait\n// fail to compile because they can't satisfy the supertrait bound.\n\n// ---- The seal -------------------------------------------------------\n\nmod private {\n    // Public *inside* the crate, but the module `private` itself is\n    // not `pub`, so downstream users cannot write `sealed_trait::\n    // private::Sealed`. They cannot implement it, therefore they\n    // cannot implement anything that requires it.\n    pub trait Sealed {}\n}\n\n// ---- The public trait, sealed --------------------------------------\n\npub trait Format: private::Sealed {\n    fn extension(&self) -> &'static str;\n    fn render(&self, data: &[(&str, i64)]) -> String;\n}\n\n// ---- Concrete implementations (only inside this crate) -------------\n\npub struct Json;\npub struct Yaml;\n\nimpl private::Sealed for Json {}\nimpl private::Sealed for Yaml {}\n\nimpl Format for Json {\n    fn extension(&self) -> &'static str { \"json\" }\n    fn render(&self, data: &[(&str, i64)]) -> String {\n        let body: Vec<String> = data\n            .iter()\n            .map(|(k, v)| format!(\"  {:?}: {}\", k, v))\n            .collect();\n        format!(\"{{\\n{}\\n}}\", body.join(\",\\n\"))\n    }\n}\n\nimpl Format for Yaml {\n    fn extension(&self) -> &'static str { \"yaml\" }\n    fn render(&self, data: &[(&str, i64)]) -> String {\n        data.iter()\n            .map(|(k, v)| format!(\"{}: {}\", k, v))\n            .collect::<Vec<_>>()\n            .join(\"\\n\")\n    }\n}\n\n// ---- Consumer code (downstream-style) --------------------------------\n\n// Consumers of this crate can take `F: Format` as a generic bound. They\n// can CALL the trait methods, but they cannot implement Format for\n// their own types.\npub fn write_report<F: Format>(fmt: &F, data: &[(&str, i64)]) -> String {\n    let body = fmt.render(data);\n    format!(\"report.{}\\n---\\n{body}\", fmt.extension())\n}\n\nfn main() {\n    let data = &[(\"users\", 42), (\"orders\", 7)];\n    println!(\"{}\", write_report(&Json, data));\n    println!();\n    println!(\"{}\", write_report(&Yaml, data));\n}\n",
        "playground": "https://play.rust-lang.org/?version=stable&mode=debug&edition=2021&code=%2F%2F%20Sealed%20Trait%20%E2%80%94%20a%20public%20trait%20only%20your%20crate's%20types%20can%20implement.%0A%2F%2F%0A%2F%2F%20Why%20seal%3F%0A%2F%2F%20%20%20*%20You%20want%20to%20ship%20%60pub%20trait%20Format%60%20as%20a%20public%20type-level%20API%0A%2F%2F%20%20%20%20%20that%20consumers%20can%20use%20as%20a%20bound%2C%20without%20letting%20them%20add%0A%2F%2F%20%20%20%20%20implementations%20you'd%20then%20have%20to%20support%20forever.%0A%2F%2F%20%20%20*%20You%20want%20to%20refactor%20internal%20types%20freely%20%E2%80%94%20adding%20methods%2C%0A%2F%2F%20%20%20%20%20changing%20defaults%20%E2%80%94%20without%20breaking%20downstream%20impls%20that%0A%2F%2F%20%20%20%20%20don't%20exist.%0A%2F%2F%20%20%20*%20You%20want%20the%20compiler%20to%20enforce%20%22this%20trait%20is%20closed%22%20so%0A%2F%2F%20%20%20%20%20%60match%20kind%20%7B%20Format%3A%3AJson%20%3D%3E%20...%2C%20Format%3A%3AYaml%20%3D%3E%20...%20%7D%60%0A%2F%2F%20%20%20%20%20reasoning%20holds.%0A%2F%2F%0A%2F%2F%20Mechanism%3A%20a%20*supertrait*%20the%20downstream%20cannot%20name.%20Put%20it%20in%20a%0A%2F%2F%20private%20module%2C%20require%20it%20on%20the%20public%20trait%2C%20and%20only%20implement%0A%2F%2F%20it%20for%20types%20inside%20the%20crate.%20Downstream%20impls%20of%20the%20public%20trait%0A%2F%2F%20fail%20to%20compile%20because%20they%20can't%20satisfy%20the%20supertrait%20bound.%0A%0A%2F%2F%20----%20The%20seal%20-------------------------------------------------------%0A%0Amod%20private%20%7B%0A%20%20%20%20%2F%2F%20Public%20*inside*%20the%20crate%2C%20but%20the%20module%20%60private%60%20itself%20is%0A%20%20%20%20%2F%2F%20not%20%60pub%60%2C%20so%20downstream%20users%20cannot%20write%20%60sealed_trait%3A%3A%0A%20%20%20%20%2F%2F%20private%3A%3ASealed%60.%20They%20cannot%20implement%20it%2C%20therefore%20they%0A%20%20%20%20%2F%2F%20cannot%20implement%20anything%20that%20requires%20it.%0A%20%20%20%20pub%20trait%20Sealed%20%7B%7D%0A%7D%0A%0A%2F%2F%20----%20The%20public%20trait%2C%20sealed%20--------------------------------------%0A%0Apub%20trait%20Format%3A%20private%3A%3ASealed%20%7B%0A%20%20%20%20fn%20extension(%26self)%20-%3E%20%26'static%20str%3B%0A%20%20%20%20fn%20render(%26self%2C%20data%3A%20%26%5B(%26str%2C%20i64)%5D)%20-%3E%20String%3B%0A%7D%0A%0A%2F%2F%20----%20Concrete%20implementations%20(only%20inside%20this%20crate)%20-------------%0A%0Apub%20struct%20Json%3B%0Apub%20struct%20Yaml%3B%0A%0Aimpl%20private%3A%3ASealed%20for%20Json%20%7B%7D%0Aimpl%20private%3A%3ASealed%20for%20Yaml%20%7B%7D%0A%0Aimpl%20Format%20for%20Json%20%7B%0A%20%20%20%20fn%20extension(%26self)%20-%3E%20%26'static%20str%20%7B%20%22json%22%20%7D%0A%20%20%20%20fn%20render(%26self%2C%20data%3A%20%26%5B(%26str%2C%20i64)%5D)%20-%3E%20String%20%7B%0A%20%20%20%20%20%20%20%20let%20body%3A%20Vec%3CString%3E%20%3D%20data%0A%20%20%20%20%20%20%20%20%20%20%20%20.iter()%0A%20%20%20%20%20%20%20%20%20%20%20%20.map(%7C(k%2C%20v)%7C%20format!(%22%20%20%7B%3A%3F%7D%3A%20%7B%7D%22%2C%20k%2C%20v))%0A%20%20%20%20%20%20%20%20%20%20%20%20.collect()%3B%0A%20%20%20%20%20%20%20%20format!(%22%7B%7B%5Cn%7B%7D%5Cn%7D%7D%22%2C%20body.join(%22%2C%5Cn%22))%0A%20%20%20%20%7D%0A%7D%0A%0Aimpl%20Format%20for%20Yaml%20%7B%0A%20%20%20%20fn%20extension(%26self)%20-%3E%20%26'static%20str%20%7B%20%22yaml%22%20%7D%0A%20%20%20%20fn%20render(%26self%2C%20data%3A%20%26%5B(%26str%2C%20i64)%5D)%20-%3E%20String%20%7B%0A%20%20%20%20%20%20%20%20data.iter()%0A%20%20%20%20%20%20%20%20%20%20%20%20.map(%7C(k%2C%20v)%7C%20format!(%22%7B%7D%3A%20%7B%7D%22%2C%20k%2C%20v))%0A%20%20%20%20%20%20%20%20%20%20%20%20.collect%3A%3A%3CVec%3C_%3E%3E()%0A%20%20%20%20%20%20%20%20%20%20%20%20.join(%22%5Cn%22)%0A%20%20%20%20%7D%0A%7D%0A%0A%2F%2F%20----%20Consumer%20code%20(downstream-style)%20--------------------------------%0A%0A%2F%2F%20Consumers%20of%20this%20crate%20can%20take%20%60F%3A%20Format%60%20as%20a%20generic%20bound.%20They%0A%2F%2F%20can%20CALL%20the%20trait%20methods%2C%20but%20they%20cannot%20implement%20Format%20for%0A%2F%2F%20their%20own%20types.%0Apub%20fn%20write_report%3CF%3A%20Format%3E(fmt%3A%20%26F%2C%20data%3A%20%26%5B(%26str%2C%20i64)%5D)%20-%3E%20String%20%7B%0A%20%20%20%20let%20body%20%3D%20fmt.render(data)%3B%0A%20%20%20%20format!(%22report.%7B%7D%5Cn---%5Cn%7Bbody%7D%22%2C%20fmt.extension())%0A%7D%0A%0Afn%20main()%20%7B%0A%20%20%20%20let%20data%20%3D%20%26%5B(%22users%22%2C%2042)%2C%20(%22orders%22%2C%207)%5D%3B%0A%20%20%20%20println!(%22%7B%7D%22%2C%20write_report(%26Json%2C%20data))%3B%0A%20%20%20%20println!()%3B%0A%20%20%20%20println!(%22%7B%7D%22%2C%20write_report(%26Yaml%2C%20data))%3B%0A%7D%0A"
