        "source": "// Iterator as Strategy — every iterator adapter is a Strategy pattern\n// whose \"strategy\" is a closure you pass in.\n//\n// Five examples from different families:\n//   * map              — Strategy: transform each item\n//   * filter           — Strategy: predicate\n//   * fold             — Strategy: accumulation step\n//   * sort_by          — Strategy: comparator\n//   * scan             — Strategy: stateful stepper\n//\n// Each closure is a one-line Strategy implementation that the\n// standard library's adapter parameterizes over. No trait Strategy,\n// no Box<dyn>, no ceremony.\n\nuse std::cmp::Ordering;\n\nfn main() {\n    let xs = vec![3_i64, 1, 4, 1, 5, 9, 2, 6, 5, 3];\n\n    // 1. map — Strategy: \"square each number\"\n    let squares: Vec<i64> = xs.iter().map(|&n| n * n).collect();\n    println!(\"squares: {squares:?}\");\n\n    // 2. filter — Strategy: \"keep only odd\"\n    let odd: Vec<i64> = xs.iter().copied().filter(|n| n % 2 == 1).collect();\n    println!(\"odd: {odd:?}\");\n\n    // 3. fold — Strategy: \"sum with bonus for even numbers\"\n    //    Demonstrates: the fold step function IS the algorithm.\n    let weighted = xs.iter().fold(0_i64, |acc, &n| acc + if n % 2 == 0 { 2 * n } else { n });\n    println!(\"weighted sum: {weighted}\");\n\n    // 4. sort_by — Strategy: \"comparator\". Sort by (parity, value):\n    //    evens before odds, then ascending within each group.\n    let mut ordered = xs.clone();\n    ordered.sort_by(|a, b| match (a % 2, b % 2) {\n        (0, 0) | (1, 1) => a.cmp(b),\n        (0, _) => Ordering::Less,\n        (_, _) => Ordering::Greater,\n    });\n    println!(\"sort_by parity then value: {ordered:?}\");\n\n    // 5. scan — Strategy: stateful stepper. Running cumulative sum\n    //    that stops once it exceeds 20.\n    let partials: Vec<i64> = xs.iter().scan(0_i64, |sum, &n| {\n        *sum += n;\n        if *sum > 20 { None } else { Some(*sum) }\n    }).collect();\n    println!(\"running sum until > 20: {partials:?}\");\n\n    // 6. Compose several strategies into a pipeline — no intermediate\n    //    Vec; `take_while` stops the stream eagerly.\n    let total: u64 = (0_u64..)\n        .map(|n| n * n)\n        .filter(|&sq| sq % 2 == 0)\n        .take_while(|&sq| sq < 1000)\n        .sum();\n    println!(\"sum of even squares < 1000 = {total}\");\n\n    // 7. A generic helper that accepts any \"reducer\" strategy.\n    //    Shows that YOUR API can take closures the same way std does.\n    fn reduce<I, F, T>(iter: I, init: T, step: F) -> T\n    where\n        I: IntoIterator,\n        F: FnMut(T, I::Item) -> T,\n    {\n        iter.into_iter().fold(init, step)\n    }\n\n    let joined = reduce(\n        xs.iter().map(|n| n.to_string()),\n        String::new(),\n        |mut acc, s| { if !acc.is_empty() { acc.push(','); } acc.push_str(&s); acc },\n    );\n    println!(\"joined: {joined}\");\n}\n",
        "playground": "https://play.rust-lang.org/?version=stable&mode=debug&edition=2021&code=%2F%2F%20Iterator%20as%20Strategy%20%E2%80%94%20every%20iterator%20adapter%20is%20a%20Strategy%20pattern%0A%2F%2F%20whose%20%22strategy%22%20is%20a%20closure%20you%20pass%20in.%0A%2F%2F%0A%2F%2F%20Five%20examples%20from%20different%20families%3A%0A%2F%2F%20%20%20*%20map%20%20%20%20%20%20%20%20%20%20%20%20%20%20%E2%80%94%20Strategy%3A%20transform%20each%20item%0A%2F%2F%20%20%20*%20filter%20%20%20%20%20%20%20%20%20%20%20%E2%80%94%20Strategy%3A%20predicate%0A%2F%2F%20%20%20*%20fold%20%20%20%20%20%20%20%20%20%20%20%20%20%E2%80%94%20Strategy%3A%20accumulation%20step%0A%2F%2F%20%20%20*%20sort_by%20%20%20%20%20%20%20%20%20%20%E2%80%94%20Strategy%3A%20comparator%0A%2F%2F%20%20%20*%20scan%20%20%20%20%20%20%20%20%20%20%20%20%20%E2%80%94%20Strategy%3A%20stateful%20stepper%0A%2F%2F%0A%2F%2F%20Each%20closure%20is%20a%20one-line%20Strategy%20implementation%20that%20the%0A%2F%2F%20standard%20library's%20adapter%20parameterizes%20over.%20No%20trait%20Strategy%2C%0A%2F%2F%20no%20Box%3Cdyn%3E%2C%20no%20ceremony.%0A%0Ause%20std%3A%3Acmp%3A%3AOrdering%3B%0A%0Afn%20main()%20%7B%0A%20%20%20%20let%20xs%20%3D%20vec!%5B3_i64%2C%201%2C%204%2C%201%2C%205%2C%209%2C%202%2C%206%2C%205%2C%203%5D%3B%0A%0A%20%20%20%20%2F%2F%201.%20map%20%E2%80%94%20Strategy%3A%20%22square%20each%20number%22%0A%20%20%20%20let%20squares%3A%20Vec%3Ci64%3E%20%3D%20xs.iter().map(%7C%26n%7C%20n%20*%20n).collect()%3B%0A%20%20%20%20println!(%22squares%3A%20%7Bsquares%3A%3F%7D%22)%3B%0A%0A%20%20%20%20%2F%2F%202.%20filter%20%E2%80%94%20Strategy%3A%20%22keep%20only%20odd%22%0A%20%20%20%20let%20odd%3A%20Vec%3Ci64%3E%20%3D%20xs.iter().copied().filter(%7Cn%7C%20n%20%25%202%20%3D%3D%201).collect()%3B%0A%20%20%20%20println!(%22odd%3A%20%7Bodd%3A%3F%7D%22)%3B%0A%0A%20%20%20%20%2F%2F%203.%20fold%20%E2%80%94%20Strategy%3A%20%22sum%20with%20bonus%20for%20even%20numbers%22%0A%20%20%20%20%2F%2F%20%20%20%20Demonstrates%3A%20the%20fold%20step%20function%20IS%20the%20algorithm.%0A%20%20%20%20let%20weighted%20%3D%20xs.iter().fold(0_i64%2C%20%7Cacc%2C%20%26n%7C%20acc%20%2B%20if%20n%20%25%202%20%3D%3D%200%20%7B%202%20*%20n%20%7D%20else%20%7B%20n%20%7D)%3B%0A%20%20%20%20println!(%22weighted%20sum%3A%20%7Bweighted%7D%22)%3B%0A%0A%20%20%20%20%2F%2F%204.%20sort_by%20%E2%80%94%20Strategy%3A%20%22comparator%22.%20Sort%20by%20(parity%2C%20value)%3A%0A%20%20%20%20%2F%2F%20%20%20%20evens%20before%20odds%2C%20then%20ascending%20within%20each%20group.%0A%20%20%20%20let%20mut%20ordered%20%3D%20xs.clone()%3B%0A%20%20%20%20ordered.sort_by(%7Ca%2C%20b%7C%20match%20(a%20%25%202%2C%20b%20%25%202)%20%7B%0A%20%20%20%20%20%20%20%20(0%2C%200)%20%7C%20(1%2C%201)%20%3D%3E%20a.cmp(b)%2C%0A%20%20%20%20%20%20%20%20(0%2C%20_)%20%3D%3E%20Ordering%3A%3ALess%2C%0A%20%20%20%20%20%20%20%20(_%2C%20_)%20%3D%3E%20Ordering%3A%3AGreater%2C%0A%20%20%20%20%7D)%3B%0A%20%20%20%20println!(%22sort_by%20parity%20then%20value%3A%20%7Bordered%3A%3F%7D%22)%3B%0A%0A%20%20%20%20%2F%2F%205.%20scan%20%E2%80%94%20Strategy%3A%20stateful%20stepper.%20Running%20cumulative%20sum%0A%20%20%20%20%2F%2F%20%20%20%20that%20stops%20once%20it%20exceeds%2020.%0A%20%20%20%20let%20partials%3A%20Vec%3Ci64%3E%20%3D%20xs.iter().scan(0_i64%2C%20%7Csum%2C%20%26n%7C%20%7B%0A%20%20%20%20%20%20%20%20*sum%20%2B%3D%20n%3B%0A%20%20%20%20%20%20%20%20if%20*sum%20%3E%2020%20%7B%20None%20%7D%20else%20%7B%20Some(*sum)%20%7D%0A%20%20%20%20%7D).collect()%3B%0A%20%20%20%20println!(%22running%20sum%20until%20%3E%2020%3A%20%7Bpartials%3A%3F%7D%22)%3B%0A%0A%20%20%20%20%2F%2F%206.%20Compose%20several%20strategies%20into%20a%20pipeline%20%E2%80%94%20no%20intermediate%0A%20%20%20%20%2F%2F%20%20%20%20Vec%3B%20%60take_while%60%20stops%20the%20stream%20eagerly.%0A%20%20%20%20let%20total%3A%20u64%20%3D%20(0_u64..)%0A%20%20%20%20%20%20%20%20.map(%7Cn%7C%20n%20*%20n)%0A%20%20%20%20%20%20%20%20.filter(%7C%26sq%7C%20sq%20%25%202%20%3D%3D%200)%0A%20%20%20%20%20%20%20%20.take_while(%7C%26sq%7C%20sq%20%3C%201000)%0A%20%20%20%20%20%20%20%20.sum()%3B%0A%20%20%20%20println!(%22sum%20of%20even%20squares%20%3C%201000%20%3D%20%7Btotal%7D%22)%3B%0A%0A%20%20%20%20%2F%2F%207.%20A%20generic%20helper%20that%20accepts%20any%20%22reducer%22%20strategy.%0A%20%20%20%20%2F%2F%20%20%20%20Shows%20that%20YOUR%20API%20can%20take%20closures%20the%20same%20way%20std%20does.%0A%20%20%20%20fn%20reduce%3CI%2C%20F%2C%20T%3E(iter%3A%20I%2C%20init%3A%20T%2C%20step%3A%20F)%20-%3E%20T%0A%20%20%20%20where%0A%20%20%20%20%20%20%20%20I%3A%20IntoIterator%2C%0A%20%20%20%20%20%20%20%20F%3A%20FnMut(T%2C%20I%3A%3AItem)%20-%3E%20T%2C%0A%20%20%20%20%7B%0A%20%20%20%20%20%20%20%20iter.into_iter().fold(init%2C%20step)%0A%20%20%20%20%7D%0A%0A%20%20%20%20let%20joined%20%3D%20reduce(%0A%20%20%20%20%20%20%20%20xs.iter().map(%7Cn%7C%20n.to_string())%2C%0A%20%20%20%20%20%20%20%20String%3A%3Anew()%2C%0A%20%20%20%20%20%20%20%20%7Cmut%20acc%2C%20s%7C%20%7B%20if%20!acc.is_empty()%20%7B%20acc.push('%2C')%3B%20%7D%20acc.push_str(%26s)%3B%20acc%20%7D%2C%0A%20%20%20%20)%3B%0A%20%20%20%20println!(%22joined%3A%20%7Bjoined%7D%22)%3B%0A%7D%0A"
